SELECT COUNT(*) AS QUANTIDADE FROM LATTES_P_PRODBIB PP JOIN LATTES_PRODBIB PB ON PB.PK = PP.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = PP.FK_SIAPE WHERE LOWER(PB.TIPO) LIKE LOWER('cap%ulo de livro') AND TRIM(PB.ANO) = '2025' AND LOWER(S.SIGLA_CAMPUS) = LOWER('luz') AND (LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%educa%' OR LOWER(COALESCE(S.AREA_INGRESSO_OG, '')) LIKE '%educa%')